import React, { useState } from 'react';
import toast from 'react-hot-toast';
import { phongAPI } from '../services/api';
import './TimPhong.css';

const fmt = n => new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(n || 0);

export default function TimPhong() {
  const [filters, setFilters] = useState({ giaTienMin:'', giaTienMax:'', diaChi:'', soNguoi:'' });
  const [phongs, setPhongs] = useState([]);
  const [loading, setLoading] = useState(false);
  const [searched, setSearched] = useState(false);

  const handleSearch = async e => {
    e.preventDefault();
    setLoading(true);
    try {
      const params = {};
      if (filters.giaTienMin) params.giaTienMin = filters.giaTienMin;
      if (filters.giaTienMax) params.giaTienMax = filters.giaTienMax;
      if (filters.diaChi) params.diaChi = filters.diaChi;
      if (filters.soNguoi) params.soNguoi = filters.soNguoi;
      const res = await phongAPI.timKiem(params);
      setPhongs(res.data.data || []);
      setSearched(true);
    } catch { toast.error('Tìm kiếm thất bại'); }
    setLoading(false);
  };

  const set = (k, v) => setFilters(f => ({...f, [k]: v}));

  return (
    <div className="container page-wrapper">
      <h1 className="section-title">🔍 Lọc phòng nâng cao</h1>
      <p className="section-subtitle">Tìm phòng theo tiêu chí cụ thể của bạn</p>

      <form onSubmit={handleSearch} className="card" style={{ marginBottom: 28 }}>
        <div className="card-body">
          <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit, minmax(200px, 1fr))', gap: 16 }}>
            <div className="form-group" style={{ marginBottom: 0 }}>
              <label className="form-label">Khu vực</label>
              <input className="form-control" placeholder="Quận, phường..." value={filters.diaChi} onChange={e => set('diaChi', e.target.value)} />
            </div>
            <div className="form-group" style={{ marginBottom: 0 }}>
              <label className="form-label">Giá tối thiểu</label>
              <input className="form-control" type="number" placeholder="0" value={filters.giaTienMin} onChange={e => set('giaTienMin', e.target.value)} />
            </div>
            <div className="form-group" style={{ marginBottom: 0 }}>
              <label className="form-label">Giá tối đa</label>
              <input className="form-control" type="number" placeholder="10,000,000" value={filters.giaTienMax} onChange={e => set('giaTienMax', e.target.value)} />
            </div>
            <div className="form-group" style={{ marginBottom: 0 }}>
              <label className="form-label">Số người tối thiểu</label>
              <input className="form-control" type="number" min="1" placeholder="2" value={filters.soNguoi} onChange={e => set('soNguoi', e.target.value)} />
            </div>
          </div>
          <button type="submit" className="btn btn-primary" style={{ marginTop: 16 }} disabled={loading}>
            {loading ? '⏳ Đang tìm...' : '🔍 Tìm phòng'}
          </button>
        </div>
      </form>

      {/* Map placeholder */}
      <div className="map-placeholder card" style={{ marginBottom: 28 }}>
        <div className="card-body" style={{ textAlign:'center', padding: '40px' }}>
          <div style={{ fontSize: 56 }}>🗺️</div>
          <h3 style={{ marginTop: 12 }}>Bản đồ tích hợp</h3>
          <p style={{ color:'var(--text-muted)', marginTop: 8 }}>
            Tích hợp Google Maps API / Leaflet để hiển thị vị trí phòng.<br />
            Cài <code>react-leaflet</code> và thêm API key để kích hoạt.
          </p>
        </div>
      </div>

      {/* Results */}
      {searched && (
        <>
          <h3 style={{ marginBottom: 16 }}>Kết quả: <strong>{phongs.length}</strong> phòng</h3>
          {phongs.length === 0 ? (
            <div className="empty-state"><div className="empty-state-icon">😔</div><p>Không tìm thấy phòng phù hợp.</p></div>
          ) : (
            <div className="grid-3">
              {phongs.map(p => (
                <div key={p.maPhong} className="card phong-item">
                  <div className="card-body">
                    <h4 style={{ fontWeight: 700, marginBottom: 8 }}>{p.title}</h4>
                    <div style={{ fontSize: 20, fontWeight: 800, color:'var(--primary)' }}>{fmt(p.giaTien)}/tháng</div>
                    <div style={{ color:'var(--text-muted)', fontSize: 13, marginTop: 6 }}>📍 {p.diaChi}</div>
                    <div style={{ display:'flex', justifyContent:'space-between', marginTop: 12 }}>
                      <span style={{ fontSize: 13 }}>👥 {p.soNguoiHienTai}/{p.soNguoiToiDa} người</span>
                      <span className={`badge ${p.trangThai === 'San sang' ? 'badge-success' : 'badge-danger'}`}>
                        {p.trangThai === 'San sang' ? 'Còn trống' : 'Đã đầy'}
                      </span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </>
      )}
    </div>
  );
}
