import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import useAuthStore from '../store/authStore';
import './Auth.css';

export function DangNhap() {
  const [form, setForm] = useState({ email: '', matKhau: '' });
  const { dangNhap, loading, error, clearError } = useAuthStore();
  const navigate = useNavigate();

  const handleSubmit = async e => {
    e.preventDefault();
    const ok = await dangNhap(form.email, form.matKhau);

    if (ok) {
      toast.success('Dang nhap thanh cong!');
      navigate('/');
      return;
    }

    toast.error(useAuthStore.getState().error || 'Dang nhap that bai');
  };

  const updateField = (key, value) => {
    clearError();
    setForm(current => ({ ...current, [key]: value }));
  };

  return (
    <div className="auth-wrapper">
      <div className="auth-card card">
        <div className="card-body">
          <div className="auth-logo">RoomMate</div>
          <div className="auth-kicker">Secure Access</div>
          <h2 className="auth-title">Dang nhap</h2>
          <p className="auth-subtitle">Quay lai bang dieu khien de tiep tuc quan ly phong va giao dich.</p>
          {error && <div className="alert alert-danger">{error}</div>}
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label className="form-label">Email</label>
              <input
                className="form-control"
                type="email"
                required
                autoComplete="email"
                value={form.email}
                onChange={e => updateField('email', e.target.value)}
                placeholder="example@email.com"
              />
            </div>
            <div className="form-group">
              <label className="form-label">Mat khau</label>
              <input
                className="form-control"
                type="password"
                required
                autoComplete="current-password"
                value={form.matKhau}
                onChange={e => updateField('matKhau', e.target.value)}
                placeholder="Nhap mat khau"
              />
            </div>
            <button className="btn btn-primary btn-block auth-submit" disabled={loading}>
              {loading ? 'Dang dang nhap...' : 'Dang nhap'}
            </button>
          </form>
          <p className="auth-footer">
            Chua co tai khoan? <Link to="/dang-ky">Dang ky ngay</Link>
          </p>
        </div>
      </div>
    </div>
  );
}

export default DangNhap;
